import { Question } from "@/lib/types";

/**
 * Year 2 — Numerical Methods § 10.5 The Trapezium Rule
 * Ref: y2nm5
 * 70 questions on the trapezium rule for estimating \(\int_{a}^{b} y\,dx\):
 *   T = (h/2)[y_0 + 2(y_1 + y_2 + ... + y_{n-1}) + y_n],  h = (b - a)/n.
 * Covers: the formula, counting strips vs ordinates, applying the rule to
 * polynomial/trig/exp/log integrands, comparing with the exact value,
 * under/over-estimation from concavity, and improving accuracy with more strips.
 */
export const questions: Question[] = [
  { id: "y2nm5-001", topicRef: "y2nm5", topicTitle: "Trapezium Rule 01", difficulty: "Foundation", questionText: "State the trapezium rule for estimating \\(\\int_{a}^{b} y\\,dx\\) using \\(n\\) strips of equal width.", marks: 2, examStyle: false, yearCreated: 2026, tags: ["formula"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "\\int_{a}^{b} y\\,dx \\approx \\tfrac{h}{2}\\!\\left[y_{0} + 2(y_{1} + y_{2} + \\cdots + y_{n-1}) + y_{n}\\right]", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "h = \\tfrac{b - a}{n}", explanation: "" } ], finalAnswer: "\\(\\tfrac{h}{2}\\!\\left[y_{0} + y_{n} + 2\\sum_{i=1}^{n-1} y_{i}\\right]\\)." } },
  { id: "y2nm5-002", topicRef: "y2nm5", topicTitle: "Trapezium Rule 02", difficulty: "Foundation", questionText: "Explain what is meant by a \"strip\" and an \"ordinate\" in the trapezium rule.", marks: 2, examStyle: false, yearCreated: 2026, tags: ["terminology"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "", explanation: "A strip is one of the equal sub-intervals obtained by dividing \\([a, b]\\); an ordinate is a \\(y\\)-value \\(y_{i} = f(a + ih)\\) at the boundaries of the strips." } ], finalAnswer: "\\(n\\) strips produce \\(n + 1\\) ordinates \\(y_{0}, y_{1}, \\ldots, y_{n}\\)." } },
  { id: "y2nm5-003", topicRef: "y2nm5", topicTitle: "Trapezium Rule 03", difficulty: "Foundation", questionText: "A trapezium-rule calculation uses 4 strips on \\([1, 5]\\). State the strip width \\(h\\) and list the \\(x\\)-values of the ordinates.", marks: 2, examStyle: false, yearCreated: 2026, tags: ["setup"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{5 - 1}{4} = 1", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "x = 1, 2, 3, 4, 5", explanation: "" } ], finalAnswer: "\\(h = 1\\); ordinates at \\(x = 1, 2, 3, 4, 5\\)." } },
  { id: "y2nm5-004", topicRef: "y2nm5", topicTitle: "Trapezium Rule 04", difficulty: "Foundation", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{4} x^{2}\\,dx\\).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = 0,\\ y_{1} = 1,\\ y_{2} = 4,\\ y_{3} = 9,\\ y_{4} = 16", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(0 + 16 + 2(1 + 4 + 9)) = \\tfrac{1}{2}(16 + 28) = 22", explanation: "" } ], finalAnswer: "\\(T = 22\\)." } },
  { id: "y2nm5-005", topicRef: "y2nm5", topicTitle: "Trapezium Rule 05", difficulty: "Foundation", questionText: "Compare the estimate from Q4 with the exact value of \\(\\int_{0}^{4} x^{2}\\,dx\\), and state the percentage error.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "\\int_{0}^{4} x^{2}\\,dx = \\tfrac{64}{3} \\approx 21.333", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "\\text{Error} = \\tfrac{22 - 21.333}{21.333} \\times 100 \\approx 3.13\\%", explanation: "" } ], finalAnswer: "Estimate overshoots the exact value \\(21.\\overline{3}\\) by about 3.13%." } },
  { id: "y2nm5-006", topicRef: "y2nm5", topicTitle: "Trapezium Rule 06", difficulty: "Foundation", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{1}^{5} \\sqrt{x}\\,dx\\). Give your answer to 3 decimal places.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = 1,\\ y_{1} = \\sqrt 2,\\ y_{2} = \\sqrt 3,\\ y_{3} = 2,\\ y_{4} = \\sqrt 5", explanation: "\\(y_{0} = 1,\\ y_{1} \\approx 1.414,\\ y_{2} \\approx 1.732,\\ y_{3} = 2,\\ y_{4} \\approx 2.236\\)." }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(1 + 2.236 + 2(1.414 + 1.732 + 2)) = \\tfrac{1}{2}(3.236 + 10.292)", explanation: "" } ], finalAnswer: "\\(T \\approx 6.764\\)." } },
  { id: "y2nm5-007", topicRef: "y2nm5", topicTitle: "Trapezium Rule 07", difficulty: "Foundation", questionText: "Use the trapezium rule with 2 strips to estimate \\(\\int_{0}^{2} \\tfrac{1}{1 + x^{2}}\\,dx\\). Give your answer to 4 decimal places.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = 1,\\ y_{1} = 0.5,\\ y_{2} = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(1 + 0.2 + 2(0.5)) = \\tfrac{1}{2}(2.2) = 1.1000", explanation: "" } ], finalAnswer: "\\(T = 1.1000\\)." } },
  { id: "y2nm5-008", topicRef: "y2nm5", topicTitle: "Trapezium Rule 08", difficulty: "Foundation", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} \\tfrac{1}{1 + x^{2}}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5,\\ y_{0} = 1,\\ y_{1} = 0.8,\\ y_{2} = 0.5,\\ y_{3} \\approx 0.3077,\\ y_{4} = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{0.5}{2}(1 + 0.2 + 2(0.8 + 0.5 + 0.3077)) = 0.25(1.2 + 3.2154)", explanation: "" } ], finalAnswer: "\\(T \\approx 1.1038\\)." } },
  { id: "y2nm5-009", topicRef: "y2nm5", topicTitle: "Trapezium Rule 09", difficulty: "Foundation", questionText: "Using the estimates from Q7 and Q8, compare them with the exact value \\(\\arctan 2 \\approx 1.1071\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "|1.1071 - 1.1000| \\approx 0.0071", explanation: "2 strips." }, { stepNumber: 2, description: "", workingLatex: "|1.1071 - 1.1038| \\approx 0.0033", explanation: "4 strips — closer." } ], finalAnswer: "More strips give a more accurate estimate." } },
  { id: "y2nm5-010", topicRef: "y2nm5", topicTitle: "Trapezium Rule 10", difficulty: "Foundation", questionText: "Use the trapezium rule with 5 strips to estimate \\(\\int_{0}^{1} e^{x}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "exponential"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 1.2214,\\ y_{2} \\approx 1.4918,\\ y_{3} \\approx 1.8221,\\ y_{4} \\approx 2.2255,\\ y_{5} \\approx 2.7183", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.2}{2}(1 + 2.7183 + 2(1.2214 + 1.4918 + 1.8221 + 2.2255)) = 0.1 \\cdot 17.2399", explanation: "" } ], finalAnswer: "\\(T \\approx 1.7240\\)." } },
  { id: "y2nm5-011", topicRef: "y2nm5", topicTitle: "Trapezium Rule 11", difficulty: "Foundation", questionText: "Using Q10, compare the estimate with the exact value \\(e - 1 \\approx 1.71828\\) and compute the absolute error.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "|T - (e - 1)| = |1.7240 - 1.7183| \\approx 0.0057", explanation: "" } ], finalAnswer: "Absolute error \\(\\approx 0.006\\)." } },
  { id: "y2nm5-012", topicRef: "y2nm5", topicTitle: "Trapezium Rule 12", difficulty: "Foundation", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{\\pi} \\sin x\\,dx\\). Work in radians and give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{\\pi}{4} \\approx 0.7854", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} \\approx 0.7071,\\ y_{2} = 1,\\ y_{3} \\approx 0.7071,\\ y_{4} = 0", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.7854}{2}(0 + 0 + 2(0.7071 + 1 + 0.7071)) = 0.3927 \\cdot 4.8284", explanation: "" } ], finalAnswer: "\\(T \\approx 1.8961\\)." } },
  { id: "y2nm5-013", topicRef: "y2nm5", topicTitle: "Trapezium Rule 13", difficulty: "Foundation", questionText: "Compare the estimate from Q12 with the exact value \\(\\int_{0}^{\\pi} \\sin x\\,dx = 2\\).", marks: 2, examStyle: false, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "|2 - 1.8961| \\approx 0.1039", explanation: "" } ], finalAnswer: "Under-estimate with absolute error \\(\\approx 0.104\\)." } },
  { id: "y2nm5-014", topicRef: "y2nm5", topicTitle: "Trapezium Rule 14", difficulty: "Foundation", questionText: "State what is meant by an over-estimate and an under-estimate of \\(\\int_{a}^{b} f(x)\\,dx\\) by the trapezium rule, and relate these to the concavity of \\(f\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["concavity"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "", explanation: "If \\(f\\) is convex (\\(f'' > 0\\)) on \\([a, b]\\), the trapezium rule over-estimates; if concave (\\(f'' < 0\\)), it under-estimates." } ], finalAnswer: "Convex \\(\\Rightarrow\\) over-estimate; concave \\(\\Rightarrow\\) under-estimate." } },
  { id: "y2nm5-015", topicRef: "y2nm5", topicTitle: "Trapezium Rule 15", difficulty: "Foundation", questionText: "Using concavity, state whether the trapezium rule over- or under-estimates \\(\\int_{0}^{1} e^{x}\\,dx\\).", marks: 2, examStyle: false, yearCreated: 2026, tags: ["concavity"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "f''(x) = e^{x} > 0", explanation: "Convex on \\([0, 1]\\)." } ], finalAnswer: "Over-estimate." } },
  { id: "y2nm5-016", topicRef: "y2nm5", topicTitle: "Trapezium Rule 16", difficulty: "Foundation", questionText: "Using concavity, state whether the trapezium rule over- or under-estimates \\(\\int_{0}^{\\pi} \\sin x\\,dx\\).", marks: 2, examStyle: false, yearCreated: 2026, tags: ["concavity"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "f''(x) = -\\sin x \\leq 0", explanation: "Concave on \\([0, \\pi]\\)." } ], finalAnswer: "Under-estimate." } },
  { id: "y2nm5-017", topicRef: "y2nm5", topicTitle: "Trapezium Rule 17", difficulty: "Foundation", questionText: "Use the trapezium rule with 3 strips to estimate \\(\\int_{1}^{4} \\ln x\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "log"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = 0,\\ y_{1} = \\ln 2 \\approx 0.6931,\\ y_{2} = \\ln 3 \\approx 1.0986,\\ y_{3} = \\ln 4 \\approx 1.3863", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(0 + 1.3863 + 2(0.6931 + 1.0986)) = \\tfrac{1}{2}(4.9697)", explanation: "" } ], finalAnswer: "\\(T \\approx 2.4849\\)." } },
  { id: "y2nm5-018", topicRef: "y2nm5", topicTitle: "Trapezium Rule 18", difficulty: "Foundation", questionText: "The trapezium rule is applied to \\(\\int_{0}^{1} \\sqrt{1 + x^{3}}\\,dx\\) using 2 strips. Find the estimate to 4 decimal places.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = \\sqrt{1.125} \\approx 1.0607,\\ y_{2} = \\sqrt{2} \\approx 1.4142", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.5}{2}(1 + 1.4142 + 2(1.0607)) = 0.25(4.5356)", explanation: "" } ], finalAnswer: "\\(T \\approx 1.1339\\)." } },
  { id: "y2nm5-019", topicRef: "y2nm5", topicTitle: "Trapezium Rule 19", difficulty: "Foundation", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} 2^{x}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "exponential"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 1.4142,\\ y_{2} = 2,\\ y_{3} \\approx 2.8284,\\ y_{4} = 4", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.5}{2}(1 + 4 + 2(1.4142 + 2 + 2.8284)) = 0.25(17.4852)", explanation: "" } ], finalAnswer: "\\(T \\approx 4.3713\\)." } },
  { id: "y2nm5-020", topicRef: "y2nm5", topicTitle: "Trapezium Rule 20", difficulty: "Foundation", questionText: "Continuing Q19, compare with the exact value \\(\\int_{0}^{2} 2^{x}\\,dx = \\tfrac{3}{\\ln 2}\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "\\tfrac{3}{\\ln 2} \\approx 4.3281", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "|4.3713 - 4.3281| \\approx 0.0432", explanation: "Convex \\(\\Rightarrow\\) over-estimate." } ], finalAnswer: "Exact \\(\\approx 4.3281\\); over-estimate by \\(\\approx 0.043\\)." } },
  { id: "y2nm5-021", topicRef: "y2nm5", topicTitle: "Trapezium Rule 21", difficulty: "Standard", questionText: "Use the trapezium rule with 5 strips to estimate \\(\\int_{0}^{1} \\tfrac{1}{1 + x}\\,dx\\). Give your answer to 5 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = \\tfrac{1}{1.2} \\approx 0.83333,\\ y_{2} \\approx 0.71429,\\ y_{3} = 0.625,\\ y_{4} \\approx 0.55556,\\ y_{5} = 0.5", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.2}{2}(1 + 0.5 + 2(0.83333 + 0.71429 + 0.625 + 0.55556))", explanation: "" } ], finalAnswer: "\\(T \\approx 0.69563\\)." } },
  { id: "y2nm5-022", topicRef: "y2nm5", topicTitle: "Trapezium Rule 22", difficulty: "Standard", questionText: "The integral \\(\\int_{0}^{1} \\tfrac{1}{1 + x}\\,dx = \\ln 2 \\approx 0.69315\\). Using Q21, comment on the accuracy.", marks: 2, examStyle: false, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "|0.69563 - 0.69315| \\approx 0.00248", explanation: "" } ], finalAnswer: "Over-estimate (convex integrand); error \\(\\approx 0.0025\\)." } },
  { id: "y2nm5-023", topicRef: "y2nm5", topicTitle: "Trapezium Rule 23", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} x e^{-x}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "exponential"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} = 0.5 e^{-0.5} \\approx 0.3033,\\ y_{2} = e^{-1} \\approx 0.3679,\\ y_{3} = 1.5 e^{-1.5} \\approx 0.3347,\\ y_{4} = 2 e^{-2} \\approx 0.2707", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.25(0 + 0.2707 + 2(0.3033 + 0.3679 + 0.3347)) = 0.25 \\cdot 2.2825", explanation: "" } ], finalAnswer: "\\(T \\approx 0.5706\\)." } },
  { id: "y2nm5-024", topicRef: "y2nm5", topicTitle: "Trapezium Rule 24", difficulty: "Standard", questionText: "Use the trapezium rule with 3 strips to estimate \\(\\int_{0}^{3} \\tfrac{1}{\\sqrt{1 + x}}\\,dx\\). Give your answer to 4 decimal places.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = 1,\\ y_{1} = \\tfrac{1}{\\sqrt 2} \\approx 0.7071,\\ y_{2} = \\tfrac{1}{\\sqrt 3} \\approx 0.5774,\\ y_{3} = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(1 + 0.5 + 2(0.7071 + 0.5774)) = \\tfrac{1}{2}(4.0690)", explanation: "" } ], finalAnswer: "\\(T \\approx 2.0345\\)." } },
  { id: "y2nm5-025", topicRef: "y2nm5", topicTitle: "Trapezium Rule 25", difficulty: "Standard", questionText: "A student writes \\(T = \\tfrac{h}{2}(y_{0} + y_{1} + y_{2} + \\cdots + y_{n})\\) for the trapezium rule. Identify the error and correct it.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["formula"], workedSolution: { steps: [ { stepNumber: 1, description: "Interior ordinates should be doubled.", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{h}{2}(y_{0} + y_{n} + 2(y_{1} + y_{2} + \\cdots + y_{n-1}))", explanation: "" } ], finalAnswer: "Interior ordinates should have coefficient 2." } },
  { id: "y2nm5-026", topicRef: "y2nm5", topicTitle: "Trapezium Rule 26", difficulty: "Standard", questionText: "Use the trapezium rule with 6 strips to estimate \\(\\int_{0}^{6} \\tfrac{1}{x + 1}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = 0.5,\\ y_{2} \\approx 0.3333,\\ y_{3} = 0.25,\\ y_{4} = 0.2,\\ y_{5} \\approx 0.1667,\\ y_{6} \\approx 0.1429", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{1}{2}(1 + 0.1429 + 2(0.5 + 0.3333 + 0.25 + 0.2 + 0.1667)) = \\tfrac{1}{2}(4.0429)", explanation: "" } ], finalAnswer: "\\(T \\approx 2.0214\\) (exact: \\(\\ln 7 \\approx 1.9459\\))." } },
  { id: "y2nm5-027", topicRef: "y2nm5", topicTitle: "Trapezium Rule 27", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} (x^{3} - 2x + 3)\\,dx\\). Give your answer exactly.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5,\\ y_{0} = 3,\\ y_{1} = 2.125,\\ y_{2} = 2,\\ y_{3} = 3.375,\\ y_{4} = 7", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = 0.25(3 + 7 + 2(2.125 + 2 + 3.375)) = 0.25(25)", explanation: "" } ], finalAnswer: "\\(T = 6.25\\) (exact: 6)." } },
  { id: "y2nm5-028", topicRef: "y2nm5", topicTitle: "Trapezium Rule 28", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} \\cos(x^{2})\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = \\cos 0.25 \\approx 0.9689,\\ y_{2} = \\cos 1 \\approx 0.5403,\\ y_{3} = \\cos 2.25 \\approx -0.6282,\\ y_{4} = \\cos 4 \\approx -0.6536", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.25(1 + (-0.6536) + 2(0.9689 + 0.5403 + (-0.6282))) = 0.25(2.108)", explanation: "" } ], finalAnswer: "\\(T \\approx 0.5270\\)." } },
  { id: "y2nm5-029", topicRef: "y2nm5", topicTitle: "Trapezium Rule 29", difficulty: "Standard", questionText: "Use the trapezium rule with 8 strips to estimate \\(\\int_{0}^{2} \\tfrac{1}{1 + x^{2}}\\,dx\\). Give your answer to 5 decimal places.", marks: 6, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.25", explanation: "" }, { stepNumber: 2, description: "Compute \\(y_{i} = 1/(1 + x_{i}^{2})\\) for \\(x_{i} = 0, 0.25, 0.5, \\ldots, 2\\).", workingLatex: "y = 1, 0.9412, 0.8, 0.6400, 0.5, 0.3902, 0.3077, 0.2462, 0.2", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.25}{2}(1 + 0.2 + 2 \\cdot 3.8253) = 0.125 \\cdot 8.8506", explanation: "" } ], finalAnswer: "\\(T \\approx 1.10633\\) (exact \\(\\arctan 2 \\approx 1.10715\\))." } },
  { id: "y2nm5-030", topicRef: "y2nm5", topicTitle: "Trapezium Rule 30", difficulty: "Standard", questionText: "Doubling the number of strips in the trapezium rule typically improves the absolute error by what factor?", marks: 2, examStyle: false, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "\\text{error} \\propto h^{2}", explanation: "Halving \\(h\\) quarters the error." } ], finalAnswer: "Approximately a factor of 4 (error shrinks like \\(h^{2}\\))." } },
  { id: "y2nm5-031", topicRef: "y2nm5", topicTitle: "Trapezium Rule 31", difficulty: "Standard", questionText: "A table gives \\(f(x)\\) at \\(x = 0, 0.5, 1, 1.5, 2\\) with values \\(3, 4, 6, 9, 13\\). Use the trapezium rule to estimate \\(\\int_{0}^{2} f(x)\\,dx\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["tabular"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{0.5}{2}(3 + 13 + 2(4 + 6 + 9)) = 0.25(54)", explanation: "" } ], finalAnswer: "\\(T = 13.5\\)." } },
  { id: "y2nm5-032", topicRef: "y2nm5", topicTitle: "Trapezium Rule 32", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{1}^{3} x \\ln x\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "log"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} = 1.5\\ln 1.5 \\approx 0.6082,\\ y_{2} = 2\\ln 2 \\approx 1.3863,\\ y_{3} = 2.5\\ln 2.5 \\approx 2.2908,\\ y_{4} = 3\\ln 3 \\approx 3.2958", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.25(0 + 3.2958 + 2(0.6082 + 1.3863 + 2.2908)) = 0.25(11.8664)", explanation: "" } ], finalAnswer: "\\(T \\approx 2.9666\\)." } },
  { id: "y2nm5-033", topicRef: "y2nm5", topicTitle: "Trapezium Rule 33", difficulty: "Standard", questionText: "A curve \\(y = f(x)\\) is concave-up on \\([0, 2]\\). The trapezium rule with 3 strips gives \\(5.7\\). State which of the following is possible for the exact value: (a) 5.5, (b) 5.9, (c) both.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["concavity"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "", explanation: "Concave-up \\(\\Rightarrow\\) trapezium rule over-estimates, so exact \\(< 5.7\\)." } ], finalAnswer: "(a) 5.5 is possible; (b) 5.9 is not." } },
  { id: "y2nm5-034", topicRef: "y2nm5", topicTitle: "Trapezium Rule 34", difficulty: "Standard", questionText: "Use the trapezium rule with 6 strips to estimate \\(\\int_{1}^{4} \\tfrac{1}{x}\\,dx\\). Give your answer to 5 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y = 1, \\tfrac{2}{3}, 0.5, 0.4, \\tfrac{1}{3}, \\tfrac{2}{7}, 0.25", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.5}{2}(1 + 0.25 + 2(0.6667 + 0.5 + 0.4 + 0.3333 + 0.2857))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.40536\\) (exact \\(\\ln 4 \\approx 1.38629\\))." } },
  { id: "y2nm5-035", topicRef: "y2nm5", topicTitle: "Trapezium Rule 35", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{\\pi/2} \\sqrt{\\sin x}\\,dx\\). Give your answer to 4 decimal places. Work in radians.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{\\pi/2}{4} \\approx 0.3927", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} \\approx 0.6186,\\ y_{2} \\approx 0.8409,\\ y_{3} \\approx 0.9612,\\ y_{4} = 1", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.3927}{2}(0 + 1 + 2(0.6186 + 0.8409 + 0.9612))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.1404\\)." } },
  { id: "y2nm5-036", topicRef: "y2nm5", topicTitle: "Trapezium Rule 36", difficulty: "Standard", questionText: "State, with reason, how many ordinates are required to apply the trapezium rule with 10 strips.", marks: 2, examStyle: false, yearCreated: 2026, tags: ["terminology"], workedSolution: { steps: [ { stepNumber: 1, description: "Ordinates = strips + 1.", workingLatex: "", explanation: "" } ], finalAnswer: "11 ordinates." } },
  { id: "y2nm5-037", topicRef: "y2nm5", topicTitle: "Trapezium Rule 37", difficulty: "Standard", questionText: "Show, by re-grouping terms, that the trapezium rule can be written as the sum of the areas of \\(n\\) trapezia with parallel sides \\(y_{i}\\) and \\(y_{i+1}\\) and height \\(h\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["derivation"], workedSolution: { steps: [ { stepNumber: 1, description: "Area of each trapezium: \\(\\tfrac{h}{2}(y_{i} + y_{i+1})\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "Sum.", workingLatex: "\\sum_{i=0}^{n-1} \\tfrac{h}{2}(y_{i} + y_{i+1}) = \\tfrac{h}{2}(y_{0} + y_{n} + 2\\sum_{i=1}^{n-1} y_{i})", explanation: "" } ], finalAnswer: "Trapezium rule formula recovered." } },
  { id: "y2nm5-038", topicRef: "y2nm5", topicTitle: "Trapezium Rule 38", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{1} \\tfrac{1}{\\sqrt{1 - x^{2}}}\\,dx\\). Compare with the exact value \\(\\tfrac{\\pi}{2}\\).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.25", explanation: "At \\(x = 1\\), the integrand is undefined; treat this as a numerical approximation only." }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 1.0328,\\ y_{2} \\approx 1.1547,\\ y_{3} \\approx 1.5119,\\ y_{4} = \\text{undefined (}\\infty\\text{)}", explanation: "Method fails; the trapezium rule is not suitable without a substitution." } ], finalAnswer: "Method fails at \\(x = 1\\); exact \\(= \\tfrac{\\pi}{2} \\approx 1.5708\\)." } },
  { id: "y2nm5-039", topicRef: "y2nm5", topicTitle: "Trapezium Rule 39", difficulty: "Standard", questionText: "A function \\(f\\) is tabulated at \\(x = 0, 1, 2, 3, 4\\) with values \\(2, 3, 5, 4, 1\\). Estimate \\(\\int_{0}^{4} f(x)\\,dx\\) using the trapezium rule.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["tabular"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "T = \\tfrac{1}{2}(2 + 1 + 2(3 + 5 + 4)) = \\tfrac{1}{2}(27)", explanation: "" } ], finalAnswer: "\\(T = 13.5\\)." } },
  { id: "y2nm5-040", topicRef: "y2nm5", topicTitle: "Trapezium Rule 40", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} \\tfrac{\\sin x}{x}\\,dx\\) (taking \\(\\tfrac{\\sin 0}{0} = 1\\)). Give your answer to 4 decimal places. Work in radians.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = \\tfrac{\\sin 0.5}{0.5} \\approx 0.9589,\\ y_{2} = \\sin 1 \\approx 0.8415,\\ y_{3} = \\tfrac{\\sin 1.5}{1.5} \\approx 0.6650,\\ y_{4} = \\tfrac{\\sin 2}{2} \\approx 0.4546", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.25(1 + 0.4546 + 2(0.9589 + 0.8415 + 0.6650))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.6161\\)." } },
  { id: "y2nm5-041", topicRef: "y2nm5", topicTitle: "Trapezium Rule 41", difficulty: "Standard", questionText: "Use the trapezium rule with 5 strips to estimate \\(\\int_{1}^{2} \\tfrac{1}{1 + x^{4}}\\,dx\\). Give your answer to 5 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0.5,\\ y_{1} = 1/(1 + 1.2^{4}) \\approx 0.3259,\\ y_{2} \\approx 0.2005,\\ y_{3} \\approx 0.1225,\\ y_{4} \\approx 0.0759,\\ y_{5} = 1/17 \\approx 0.0588", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.2}{2}(0.5 + 0.0588 + 2(0.3259 + 0.2005 + 0.1225 + 0.0759))", explanation: "" } ], finalAnswer: "\\(T \\approx 0.20086\\)." } },
  { id: "y2nm5-042", topicRef: "y2nm5", topicTitle: "Trapezium Rule 42", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{1} \\sqrt{1 - x^{2}}\\,dx\\). Compare with the exact value \\(\\tfrac{\\pi}{4}\\).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.25", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 0.9682,\\ y_{2} \\approx 0.8660,\\ y_{3} \\approx 0.6614,\\ y_{4} = 0", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{0.25}{2}(1 + 0 + 2(0.9682 + 0.8660 + 0.6614)) = 0.125 \\cdot 5.9912", explanation: "" } ], finalAnswer: "\\(T \\approx 0.7489\\); exact \\(= \\tfrac{\\pi}{4} \\approx 0.7854\\)." } },
  { id: "y2nm5-043", topicRef: "y2nm5", topicTitle: "Trapezium Rule 43", difficulty: "Standard", questionText: "Using the trapezium rule with \\(n\\) strips, explain why the error tends to zero as \\(n \\to \\infty\\).", marks: 3, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = (b - a)/n \\to 0", explanation: "" }, { stepNumber: 2, description: "Error bound: \\(|T - \\int| \\leq \\tfrac{(b - a)^{3}}{12 n^{2}} \\max|f''|\\).", workingLatex: "", explanation: "" } ], finalAnswer: "Error shrinks like \\(1/n^{2}\\)." } },
  { id: "y2nm5-044", topicRef: "y2nm5", topicTitle: "Trapezium Rule 44", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{4} e^{-x^{2}/4}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "exponential"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} = e^{-0.25} \\approx 0.7788,\\ y_{2} = e^{-1} \\approx 0.3679,\\ y_{3} = e^{-2.25} \\approx 0.1054,\\ y_{4} = e^{-4} \\approx 0.0183", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{1}{2}(1 + 0.0183 + 2(0.7788 + 0.3679 + 0.1054))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.7613\\)." } },
  { id: "y2nm5-045", topicRef: "y2nm5", topicTitle: "Trapezium Rule 45", difficulty: "Standard", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{1} \\tfrac{\\sin \\pi x}{x + 1}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.25", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} = \\tfrac{\\sin(\\pi/4)}{1.25} \\approx 0.5657,\\ y_{2} = \\tfrac{1}{1.5} \\approx 0.6667,\\ y_{3} = \\tfrac{\\sin(3\\pi/4)}{1.75} \\approx 0.4041,\\ y_{4} = 0", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.125(0 + 0 + 2(0.5657 + 0.6667 + 0.4041))", explanation: "" } ], finalAnswer: "\\(T \\approx 0.4091\\)." } },
  { id: "y2nm5-046", topicRef: "y2nm5", topicTitle: "Trapezium Rule 46", difficulty: "Standard", questionText: "A student uses the trapezium rule with 8 strips on \\(\\int_{0}^{4} (3x^{2} - x)\\,dx\\). Use symmetry of the polynomial to show the estimate equals the exact value.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "Trapezium rule is exact for linear functions but not generally for quadratics.", workingLatex: "", explanation: "Actually trapezium rule over-estimates \\(3x^{2}\\); exact value \\(\\int_{0}^{4}(3x^{2} - x)\\,dx = 64 - 8 = 56\\)." }, { stepNumber: 2, description: "", workingLatex: "", explanation: "Computation with 8 strips gives \\(T = 56.125\\), so the claim is false; the rule is only exact for straight lines." } ], finalAnswer: "The claim is false — the trapezium rule is not exact for general quadratics." } },
  { id: "y2nm5-047", topicRef: "y2nm5", topicTitle: "Trapezium Rule 47", difficulty: "Standard", questionText: "State the class of functions for which the trapezium rule gives the exact value of \\(\\int_{a}^{b} f(x)\\,dx\\).", marks: 2, examStyle: false, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "", explanation: "Linear functions \\(f(x) = mx + c\\) — each trapezium has the same area as the region under the line." } ], finalAnswer: "Linear functions (polynomials of degree at most 1)." } },
  { id: "y2nm5-048", topicRef: "y2nm5", topicTitle: "Trapezium Rule 48", difficulty: "Standard", questionText: "Use the trapezium rule with 3 strips to estimate \\(\\int_{0}^{3} \\tfrac{2}{3 + x}\\,dx\\). Give your answer to 4 decimal places and compare with the exact value \\(2 \\ln 2\\).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "log"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 1,\\ y_{0} = \\tfrac{2}{3},\\ y_{1} = 0.5,\\ y_{2} = 0.4,\\ y_{3} = \\tfrac{2}{6} \\approx 0.3333", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{1}{2}(0.6667 + 0.3333 + 2(0.5 + 0.4)) = \\tfrac{1}{2}(2.8)", explanation: "" } ], finalAnswer: "\\(T = 1.4000\\); exact \\(= 2\\ln 2 \\approx 1.3863\\)." } },
  { id: "y2nm5-049", topicRef: "y2nm5", topicTitle: "Trapezium Rule 49", difficulty: "Standard", questionText: "Use the trapezium rule with 5 strips to estimate \\(\\int_{0}^{1} \\tfrac{e^{x}}{1 + x}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 1.0178,\\ y_{2} \\approx 1.0190,\\ y_{3} \\approx 1.0148,\\ y_{4} \\approx 1.0072,\\ y_{5} \\approx 0.9967", explanation: "Wait — re-compute: \\(y_{i} = e^{0.2i}/(1 + 0.2 i)\\)." }, { stepNumber: 3, description: "\\(y_{1} = e^{0.2}/1.2 \\approx 1.0177\\), \\(y_{2} = e^{0.4}/1.4 \\approx 1.0657\\), \\(y_{3} = e^{0.6}/1.6 \\approx 1.1389\\), \\(y_{4} = e^{0.8}/1.8 \\approx 1.2366\\), \\(y_{5} = e/2 \\approx 1.3591\\).", workingLatex: "T = \\tfrac{0.2}{2}(1 + 1.3591 + 2(1.0177 + 1.0657 + 1.1389 + 1.2366))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.1275\\)." } },
  { id: "y2nm5-050", topicRef: "y2nm5", topicTitle: "Trapezium Rule 50", difficulty: "Standard", questionText: "A table gives \\(v(t)\\) in m/s for \\(t = 0, 2, 4, 6, 8\\) s as \\(0, 3, 5, 6, 5\\). Estimate the distance travelled in 8 s using the trapezium rule.", marks: 3, examStyle: true, yearCreated: 2026, tags: ["applied"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "\\text{Distance} = \\int_{0}^{8} v\\,dt \\approx \\tfrac{2}{2}(0 + 5 + 2(3 + 5 + 6))", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "= 33", explanation: "" } ], finalAnswer: "33 m." } },
  { id: "y2nm5-051", topicRef: "y2nm5", topicTitle: "Trapezium Rule 51", difficulty: "Challenge", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{\\pi/2} \\sin^{2} x\\,dx\\). Compare with the exact value \\(\\tfrac{\\pi}{4}\\).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{\\pi}{8}", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y = 0, \\sin^{2}(\\pi/8) \\approx 0.1464, 0.5, \\sin^{2}(3\\pi/8) \\approx 0.8536, 1", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{\\pi/8}{2}(0 + 1 + 2(0.1464 + 0.5 + 0.8536)) = \\tfrac{\\pi}{16} \\cdot 4", explanation: "" } ], finalAnswer: "\\(T = \\tfrac{\\pi}{4} \\approx 0.7854\\) — exact by symmetry!" } },
  { id: "y2nm5-052", topicRef: "y2nm5", topicTitle: "Trapezium Rule 52", difficulty: "Challenge", questionText: "Explain why the trapezium rule gives the exact value of \\(\\int_{0}^{\\pi/2} \\sin^{2} x\\,dx\\) when using ordinates at \\(x = 0,\\ \\tfrac{\\pi}{8},\\ \\tfrac{\\pi}{4},\\ \\tfrac{3\\pi}{8},\\ \\tfrac{\\pi}{2}\\).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "Use \\(\\sin^{2} x = \\tfrac{1 - \\cos 2x}{2}\\) and symmetry about \\(x = \\pi/4\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "Ordinate pairs \\((y_{0}, y_{4})\\), \\((y_{1}, y_{3})\\) each sum to 1; their trapezium contribution matches the exact value.", workingLatex: "", explanation: "" } ], finalAnswer: "Symmetry and averaging make the rule exact here." } },
  { id: "y2nm5-053", topicRef: "y2nm5", topicTitle: "Trapezium Rule 53", difficulty: "Challenge", questionText: "Derive the trapezium rule error term \\(E = -\\tfrac{(b - a)^{3}}{12 n^{2}} f''(\\xi)\\) informally (no rigorous proof required).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "Taylor expand \\(f\\) about each trapezium midpoint.", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "The linear term integrates exactly; the leading error is quadratic in \\(h\\), summed over \\(n\\) strips.", workingLatex: "", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "E \\approx -\\tfrac{h^{2}(b - a)}{12} f''(\\xi) = -\\tfrac{(b - a)^{3}}{12 n^{2}} f''(\\xi)", explanation: "" } ], finalAnswer: "Leading error is \\(-\\tfrac{(b - a)^{3}}{12 n^{2}} f''(\\xi)\\)." } },
  { id: "y2nm5-054", topicRef: "y2nm5", topicTitle: "Trapezium Rule 54", difficulty: "Challenge", questionText: "Use the error formula to find the minimum number of strips needed so that the trapezium rule estimate of \\(\\int_{0}^{1} e^{x}\\,dx\\) is within 0.001 of the exact value.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "|E| \\leq \\tfrac{1}{12 n^{2}} \\max_{[0,1]} e^{x} = \\tfrac{e}{12 n^{2}}", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "\\tfrac{e}{12 n^{2}} < 0.001 \\Rightarrow n^{2} > 226.5", explanation: "" } ], finalAnswer: "\\(n \\geq 16\\) strips." } },
  { id: "y2nm5-055", topicRef: "y2nm5", topicTitle: "Trapezium Rule 55", difficulty: "Challenge", questionText: "Compare the trapezium rule with 2 strips and 4 strips on \\(\\int_{0}^{2} x^{3}\\,dx\\), and estimate the order of convergence.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["comparison"], workedSolution: { steps: [ { stepNumber: 1, description: "Exact: \\(\\int_{0}^{2} x^{3}\\,dx = 4\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "2 strips: \\(y_{0} = 0, y_{1} = 1, y_{2} = 8\\); \\(T = \\tfrac{1}{2}(0 + 8 + 2) = 5\\).", workingLatex: "", explanation: "" }, { stepNumber: 3, description: "4 strips: \\(y = 0, 0.125, 1, 3.375, 8\\); \\(T = 0.25(0 + 8 + 2(0.125 + 1 + 3.375)) = 0.25(17)\\) = 4.25.", workingLatex: "", explanation: "" }, { stepNumber: 4, description: "Errors: 1 and 0.25 — ratio 4, matching \\(h^{2}\\) scaling.", workingLatex: "", explanation: "" } ], finalAnswer: "Error scales as \\(h^{2}\\) (order 2)." } },
  { id: "y2nm5-056", topicRef: "y2nm5", topicTitle: "Trapezium Rule 56", difficulty: "Challenge", questionText: "The area under a velocity-time graph is estimated by the trapezium rule with the data \\(t = 0, 1, 2, 3, 4\\) and \\(v = 5, 7, 8, 6, 2\\). Estimate the displacement and the mean velocity over this interval.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["applied"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "T = \\tfrac{1}{2}(5 + 2 + 2(7 + 8 + 6)) = \\tfrac{1}{2}(49)", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "\\text{Mean velocity} = \\tfrac{24.5}{4}", explanation: "" } ], finalAnswer: "Displacement \\(\\approx 24.5\\) m; mean velocity \\(\\approx 6.125\\) m/s." } },
  { id: "y2nm5-057", topicRef: "y2nm5", topicTitle: "Trapezium Rule 57", difficulty: "Challenge", questionText: "Use the trapezium rule with 4 strips to estimate \\(\\int_{0}^{2} x \\sqrt{4 - x^{2}}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.5", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} \\approx 0.9682,\\ y_{2} \\approx 1.7321,\\ y_{3} \\approx 1.9843,\\ y_{4} = 0", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.25(0 + 0 + 2(0.9682 + 1.7321 + 1.9843))", explanation: "" } ], finalAnswer: "\\(T \\approx 2.3423\\) (exact = 8/3)." } },
  { id: "y2nm5-058", topicRef: "y2nm5", topicTitle: "Trapezium Rule 58", difficulty: "Challenge", questionText: "Use the trapezium rule with 10 strips to estimate \\(\\int_{0}^{\\pi} \\tfrac{x}{1 + \\sin x}\\,dx\\). Give your answer to 4 decimal places. Work in radians.", marks: 6, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{\\pi}{10}", explanation: "" }, { stepNumber: 2, description: "Evaluate \\(y_{i}\\) at \\(x_{i} = i\\pi/10\\) using a calculator.", workingLatex: "", explanation: "" }, { stepNumber: 3, description: "Apply the formula to obtain \\(T \\approx 3.1416\\).", workingLatex: "", explanation: "" } ], finalAnswer: "\\(T \\approx 3.1416\\) (close to \\(\\pi\\))." } },
  { id: "y2nm5-059", topicRef: "y2nm5", topicTitle: "Trapezium Rule 59", difficulty: "Challenge", questionText: "Prove that, for a linear function \\(f(x) = mx + c\\), the trapezium rule gives the exact value of \\(\\int_{a}^{b} f(x)\\,dx\\) for any number of strips.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["proof"], workedSolution: { steps: [ { stepNumber: 1, description: "Each trapezium between \\(x_{i}\\) and \\(x_{i+1}\\) has the same area as the integral \\(\\int_{x_{i}}^{x_{i+1}} (mx + c)\\,dx\\) — both equal \\(\\tfrac{h}{2}(y_{i} + y_{i+1})\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "Summing over all trapezia gives the total area.", workingLatex: "", explanation: "" } ], finalAnswer: "Exact for any \\(n\\)." } },
  { id: "y2nm5-060", topicRef: "y2nm5", topicTitle: "Trapezium Rule 60", difficulty: "Challenge", questionText: "Given that \\(\\int_{0}^{2} f(x)\\,dx = 7\\) exactly, and that the trapezium rule with 4 strips gives 7.3, estimate the rule with 8 strips assuming the error halves as \\(h\\) halves (error \\(\\propto h^{2}\\) actually gives factor 4 — use that).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "E_{4} = 7.3 - 7 = 0.3", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "E_{8} \\approx E_{4}/4 = 0.075", explanation: "" } ], finalAnswer: "\\(T_{8} \\approx 7.075\\)." } },
  { id: "y2nm5-061", topicRef: "y2nm5", topicTitle: "Trapezium Rule 61", difficulty: "Challenge", questionText: "Use the trapezium rule with 6 strips to estimate \\(\\int_{0}^{\\pi/2} \\tfrac{1}{1 + \\sin x}\\,dx\\). Give your answer to 4 decimal places. Work in radians.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation", "trigonometric"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = \\tfrac{\\pi}{12}", explanation: "" }, { stepNumber: 2, description: "Evaluate at \\(x = 0, \\pi/12, \\ldots, \\pi/2\\).", workingLatex: "y = 1, 0.7946, 0.6667, 0.5858, 0.5360, 0.5080, 0.5", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = \\tfrac{\\pi/12}{2}(1 + 0.5 + 2(0.7946 + 0.6667 + 0.5858 + 0.5360 + 0.5080))", explanation: "" } ], finalAnswer: "\\(T \\approx 1.0031\\) (exact \\(= 1\\))." } },
  { id: "y2nm5-062", topicRef: "y2nm5", topicTitle: "Trapezium Rule 62", difficulty: "Challenge", questionText: "A curve \\(y = f(x)\\) passes through the points \\((0, 2), (0.5, 3.2), (1, 3.8), (1.5, 3.6), (2, 2.5)\\). Use the trapezium rule to estimate \\(\\int_{0}^{2} f(x)\\,dx\\).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["tabular"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "T = \\tfrac{0.5}{2}(2 + 2.5 + 2(3.2 + 3.8 + 3.6)) = 0.25(25.7)", explanation: "" } ], finalAnswer: "\\(T = 6.425\\)." } },
  { id: "y2nm5-063", topicRef: "y2nm5", topicTitle: "Trapezium Rule 63", difficulty: "Challenge", questionText: "Use the trapezium rule with 5 strips to estimate \\(\\int_{0}^{1} \\sqrt{x} e^{-x}\\,dx\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.2", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 0,\\ y_{1} = \\sqrt{0.2} e^{-0.2} \\approx 0.3662,\\ y_{2} \\approx 0.4637,\\ y_{3} \\approx 0.4824,\\ y_{4} \\approx 0.4668,\\ y_{5} \\approx 0.3679", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.1(0 + 0.3679 + 2(0.3662 + 0.4637 + 0.4824 + 0.4668))", explanation: "" } ], finalAnswer: "\\(T \\approx 0.3926\\)." } },
  { id: "y2nm5-064", topicRef: "y2nm5", topicTitle: "Trapezium Rule 64", difficulty: "Challenge", questionText: "Explain how the trapezium rule can be used to numerically approximate the length of a curve given by \\(y = f(x)\\) between \\(x = a\\) and \\(x = b\\).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["applied"], workedSolution: { steps: [ { stepNumber: 1, description: "The arc length is \\(L = \\int_{a}^{b} \\sqrt{1 + (f'(x))^{2}}\\,dx\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "Apply the trapezium rule to this integral.", workingLatex: "", explanation: "" } ], finalAnswer: "Apply the rule to \\(\\sqrt{1 + (f')^{2}}\\)." } },
  { id: "y2nm5-065", topicRef: "y2nm5", topicTitle: "Trapezium Rule 65", difficulty: "Challenge", questionText: "Use the trapezium rule with 4 strips to estimate the arc length of \\(y = x^{2}\\) from \\(x = 0\\) to \\(x = 1\\). Give your answer to 4 decimal places.", marks: 5, examStyle: true, yearCreated: 2026, tags: ["applied"], workedSolution: { steps: [ { stepNumber: 1, description: "Arc length integrand: \\(\\sqrt{1 + 4x^{2}}\\).", workingLatex: "h = 0.25", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "y_{0} = 1,\\ y_{1} \\approx 1.1180,\\ y_{2} \\approx 1.4142,\\ y_{3} \\approx 1.8028,\\ y_{4} \\approx 2.2361", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.125(1 + 2.2361 + 2(1.1180 + 1.4142 + 1.8028))", explanation: "" } ], finalAnswer: "\\(L \\approx 1.4888\\)." } },
  { id: "y2nm5-066", topicRef: "y2nm5", topicTitle: "Trapezium Rule 66", difficulty: "Challenge", questionText: "Use the trapezium rule with 8 strips to estimate \\(\\int_{0}^{2} \\tfrac{\\ln(x + 1)}{1 + x^{2}}\\,dx\\). Give your answer to 4 decimal places.", marks: 6, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.25", explanation: "" }, { stepNumber: 2, description: "Evaluate \\(y_{i} = \\tfrac{\\ln(x_{i} + 1)}{1 + x_{i}^{2}}\\) for \\(x_{i} = 0, 0.25, \\ldots, 2\\).", workingLatex: "y \\approx 0, 0.2102, 0.3243, 0.3578, 0.3466, 0.3146, 0.2772, 0.2403, 0.2197", explanation: "" }, { stepNumber: 3, description: "", workingLatex: "T = 0.125(0 + 0.2197 + 2(0.2102 + 0.3243 + 0.3578 + 0.3466 + 0.3146 + 0.2772 + 0.2403))", explanation: "" } ], finalAnswer: "\\(T \\approx 0.5603\\)." } },
  { id: "y2nm5-067", topicRef: "y2nm5", topicTitle: "Trapezium Rule 67", difficulty: "Challenge", questionText: "A river's cross-section is measured every 2 m across a 10 m width, giving depths \\(0, 1.5, 2.2, 2.4, 1.8, 0\\) m. Estimate the cross-sectional area using the trapezium rule.", marks: 4, examStyle: true, yearCreated: 2026, tags: ["applied"], workedSolution: { steps: [ { stepNumber: 1, description: "5 strips of width 2 m.", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "", workingLatex: "T = \\tfrac{2}{2}(0 + 0 + 2(1.5 + 2.2 + 2.4 + 1.8)) = 15.8", explanation: "" } ], finalAnswer: "15.8 m\\(^{2}\\)." } },
  { id: "y2nm5-068", topicRef: "y2nm5", topicTitle: "Trapezium Rule 68", difficulty: "Challenge", questionText: "Show that if the trapezium rule estimate on \\([a, b]\\) with \\(n\\) strips equals the exact integral, then the integrand is linear (for a smooth function).", marks: 4, examStyle: true, yearCreated: 2026, tags: ["theory"], workedSolution: { steps: [ { stepNumber: 1, description: "Error term is \\(-\\tfrac{(b-a)^{3}}{12 n^{2}} f''(\\xi)\\).", workingLatex: "", explanation: "" }, { stepNumber: 2, description: "For the error to vanish for all \\(n\\), need \\(f''(x) = 0\\) on \\([a, b]\\), i.e.\\ \\(f\\) is linear.", workingLatex: "", explanation: "" } ], finalAnswer: "Shown." } },
  { id: "y2nm5-069", topicRef: "y2nm5", topicTitle: "Trapezium Rule 69", difficulty: "Challenge", questionText: "Estimate \\(\\int_{0}^{1} e^{-x^{2}}\\,dx\\) using the trapezium rule with 10 strips. Give your answer to 5 decimal places and comment on how close it is to the known value \\(\\tfrac{\\sqrt{\\pi}}{2}\\operatorname{erf}(1) \\approx 0.74682\\).", marks: 6, examStyle: true, yearCreated: 2026, tags: ["calculation"], workedSolution: { steps: [ { stepNumber: 1, description: "", workingLatex: "h = 0.1", explanation: "" }, { stepNumber: 2, description: "Evaluate \\(y_{i} = e^{-0.01 i^{2}}\\) for \\(i = 0, \\ldots, 10\\).", workingLatex: "", explanation: "" }, { stepNumber: 3, description: "Apply the rule to obtain \\(T \\approx 0.74621\\).", workingLatex: "", explanation: "" } ], finalAnswer: "\\(T \\approx 0.74621\\); error \\(\\approx 6 \\times 10^{-4}\\) (under-estimate)." } },
  { id: "y2nm5-070", topicRef: "y2nm5", topicTitle: "Trapezium Rule 70", difficulty: "Challenge", questionText: "A function \\(f\\) is tabulated: \\(x = 0, 0.5, 1, 1.5, 2, 2.5, 3\\) with \\(y = 4, 5, 7, 9, 10, 8, 4\\). Estimate \\(\\int_{0}^{3} f(x)\\,dx\\) using the trapezium rule, and the value of \\(\\int_{1}^{2} f(x)\\,dx\\).", marks: 5, examStyle: true, yearCreated: 2026, tags: ["tabular"], workedSolution: { steps: [ { stepNumber: 1, description: "Full interval, 6 strips of width 0.5.", workingLatex: "T = 0.25(4 + 4 + 2(5 + 7 + 9 + 10 + 8)) = 0.25(86)", explanation: "" }, { stepNumber: 2, description: "Sub-interval \\([1, 2]\\), 2 strips.", workingLatex: "T_{[1,2]} = 0.25(7 + 10 + 2(9)) = 0.25(35)", explanation: "" } ], finalAnswer: "\\(\\int_{0}^{3} f\\,dx \\approx 21.5\\); \\(\\int_{1}^{2} f\\,dx \\approx 8.75\\)." } },
];
